import React, { useState } from 'react';
import './App.css';

function App() {
    const [objects, setObject] = useState([]);

    function newObject() {
        setObject([...objects, { id: Date.now() }]);
    }

    function mouseDownOnObject(e, id) {
        const mouseX = e.clientX;
        const mouseY = e.clientY;

        const newX = mouseX - objectSize / 2;
        const newY = mouseY - objectSize / 2;
    }

    return (
        <div className="app-container">
            <header className="header">
                <h1>🎵 Sound Landscape</h1>
            </header>
            <div className="main">
                <aside className="sidebar">
                    <button onClick={newObject}>Добавить объект</button>
                </aside>
                <div
                    className="canvas-container"
                    style={{
                        position: 'relative',
                    }}
                >
                    {objects.map((obj) => (
                        <div
                            onMouseDown={(e) => mouseDownOnObject(e, obj.id)}
                            className="obj"
                            key={obj.id}
                        ></div>
                    ))}
                </div>
            </div>
        </div>
    );
}

export default App;
